import React from "react"
import styled from "styled-components"
import { colors, fonts } from "../../utils/theme"
import { media, smoothScrollToId } from "./shared"
import ThemeToggle from "./ThemeToggle"

const StyledSidebar = styled.aside`
  position: sticky;
  top: 0;
  align-self: flex-start;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  justify-content: center;
  padding: 5rem 3rem 3rem 0;

  ${media.tablet} {
    position: relative;
    min-height: auto;
    justify-content: flex-start;
    padding: 4rem 0 0;
  }

  .portrait {
    width: 76px;
    height: 76px;
    border-radius: 50%;
    object-fit: cover;
    margin: 0 0 1.5rem;
    display: block;
    outline: 1px solid ${colors.line};
    outline-offset: 4px;
  }

  .theme-toggle {
    margin-top: 2.5rem;

    ${media.tablet} {
      margin-top: 2rem;
    }
  }

  h1 {
    font-family: ${fonts.display};
    font-size: clamp(2.6rem, 4.2vw, 3.6rem);
    font-weight: 580;
    letter-spacing: -0.03em;
    line-height: 1.02;
    margin: 0 0 1rem;
    color: ${colors.paperBright};

    em {
      font-style: italic;
      font-weight: 420;
      color: ${colors.accent};
    }
  }

  .role {
    font-family: ${fonts.mono};
    font-size: 0.8rem;
    letter-spacing: 0.14em;
    text-transform: uppercase;
    color: ${colors.paper};
    margin: 0 0 0.4rem;

    a {
      color: ${colors.accentBright};
    }
  }

  .tagline {
    font-size: 1rem;
    line-height: 1.65;
    color: ${colors.muted};
    max-width: 34ch;
    margin: 0.75rem 0 0;
  }

  nav {
    margin: 3rem 0;

    ${media.tablet} {
      display: none;
    }

    ul {
      list-style: none;
      margin: 0;
      padding: 0;
    }

    li {
      margin: 0;
    }

    a {
      display: flex;
      align-items: center;
      gap: 0.9rem;
      padding: 0.45rem 0;
      color: ${colors.faint};
      font-family: ${fonts.mono};
      font-size: 0.78rem;
      letter-spacing: 0.16em;
      text-transform: uppercase;

      &:after {
        display: none;
      }

      .idx {
        font-size: 0.65rem;
        color: ${colors.faint};
        transition: color 0.25s ease;
      }

      .tick {
        width: 1.6rem;
        height: 1px;
        background: ${colors.faint};
        transition: width 0.25s ease, background 0.25s ease;
      }

      &:hover {
        color: ${colors.paperBright};

        .tick {
          width: 2.6rem;
          background: ${colors.paper};
        }
      }

      &.active {
        color: ${colors.paperBright};

        .idx {
          color: ${colors.accent};
        }

        .tick {
          width: 3.4rem;
          background: ${colors.accent};
        }
      }
    }
  }
`

export const navItems = [
  { id: "about-me", index: "01", title: "About" },
  { id: "experience", index: "02", title: "Experience" },
  { id: "skills", index: "03", title: "Skills" },
  { id: "my-works", index: "04", title: "Works" },
  { id: "writings", index: "05", title: "Writings" },
  { id: "contact", index: "06", title: "Contact" },
]

const Sidebar = ({ activeId }) => (
  <StyledSidebar>
    <div>
      <img className="portrait" src="/krushi-portrait.png" alt="Krushi Raj Tula" />
      <h1>
        Krushi Raj
        <br />
        <em>Tula</em>
      </h1>
      <p className="role">
        Full-Stack Engineer ·{" "}
        <a
          href="https://www.paperpile.com/"
          target="_blank"
          rel="noopener noreferrer"
        >
          Paperpile
        </a>
      </p>
      <p className="tagline">
        I build search systems at 230M-document scale, developer tools people
        actually enjoy, and AI-native products.
      </p>

      <nav aria-label="Section navigation">
        <ul>
          {navItems.map(({ id, index, title }) => (
            <li key={id}>
              <a
                href={`#${id}`}
                className={activeId === id ? "active" : ""}
                aria-current={activeId === id ? "true" : undefined}
                onClick={event => {
                  event.preventDefault()
                  window.history.replaceState(null, "", `#${id}`)
                  smoothScrollToId(id)
                }}
              >
                <span className="idx">{index}</span>
                <span className="tick" />
                {title}
              </a>
            </li>
          ))}
        </ul>
      </nav>

      <ThemeToggle className="theme-toggle" />
    </div>
  </StyledSidebar>
)

export default Sidebar
